SELECT v.*, ste.site_nm AS site_nm, cd_vc.code_label AS vendor_class_cd_nm, cd_vs.code_label AS vendor_status_cd_nm FROM sy_vendor v LEFT JOIN sy_site ste ON ste.site_id = v.site_id LEFT JOIN sy_code cd_vc ON cd_vc.code_grp = 'VENDOR_CLASS' AND cd_vc.code_value = v.vendor_class_cd LEFT JOIN sy_code cd_vs ON cd_vs.code_grp = 'VENDOR_STATUS' AND cd_vs.code_value = v.vendor_status_cd
ORDER BY v.vendor_id ASC ORDER BY v.vendor_id DESC ORDER BY v.vendor_nm ASC ORDER BY v.vendor_nm DESC ORDER BY v.reg_date ASC ORDER BY v.reg_date DESC ORDER BY v.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

